-- Seed idempotente do lote 2 da galeria de exemplos (F2-5): os 20 exemplos
-- restantes de docs/EXEMPLOS-REBOBINADAS.md (6 temas × 4, menos os 4 já
-- seedados). Payload no schema do Gift.payload; fotos no R2 em
-- seed/exemplos/<slug>/<n>.png, associadas aos momentos via photoAssetId.
-- Upsert por seoSlug: re-aplicar atualiza o conteúdo sem duplicar.
INSERT INTO "Example" ("id", "persona", "name", "occasion", "payload", "seoSlug", "sortOrder", "active", "createdAt") VALUES
  ('ex_namoro_do_match', 'namorado', 'Casal do aplicativo', 'namorados',
   '{"title":"Do match ao pra sempre","recipientName":"Rê","senderName":"Dudu","assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/namoro-do-match/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-do-match/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/namoro-do-match/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-do-match/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/namoro-do-match/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-do-match/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/namoro-do-match/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-do-match/4.png","order":3}],"timeline":[{"date":"2024","title":"O match","description":"Sua bio dizia \"não curto papo furado\". Eu mandei um papo furadíssimo. Funcionou."},{"date":"2024","title":"O hambúrguer do teste","description":"Você pediu o mais caro \"pra testar se eu ia embora\". Fiquei.","photoAssetId":"ph_1"},{"date":"2024","title":"Cerimônia de desinstalação","description":"Apagamos os aplicativos juntos, um segurando o celular do outro.","photoAssetId":"ph_2"},{"date":"2025","title":"O acostamento mais romântico da serra","description":"Pneu furado, 2h de espera e a melhor conversa da minha vida.","photoAssetId":"ph_3"},{"date":"hoje","title":"Melhor update","description":"2 anos de \"cê viu isso?\" mandado ao mesmo tempo.","photoAssetId":"ph_4"}],"stats":[{"value":1,"suffix":"arraste","label":"pro lado que mudou tudo"},{"value":730,"suffix":"dias","label":"de conversa que não acabou"},{"value":3412,"suffix":"memes","label":"trocados (e contando)"}],"letter":"Rê, todo mundo ri quando conta que a gente veio de um aplicativo. Eu também rio — de sorte. Porque no meio de mil perfis eu achei a única pessoa que responde meme com meme melhor, que transforma pneu furado em história boa e silêncio em lugar confortável. Você foi o único match que virou casa. Dois anos, e eu ainda arrastaria pro lado de novo, sempre. — Dudu","theme":"vhs"}'::jsonb,
   'namoro-do-match', 20, true, CURRENT_TIMESTAMP),
  ('ex_namoro_primeiro_ano', 'namorada', 'Primeiro ano de namoro', 'namorados',
   '{"title":"365 dias do nosso primeiro beijo","recipientName":"Ícaro","senderName":"Marina","counter":{"targetDate":"2025-07-12","label":"dias desde que eu perdi a linha do \"só amigos\""},"assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/namoro-primeiro-ano/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-primeiro-ano/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/namoro-primeiro-ano/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-primeiro-ano/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/namoro-primeiro-ano/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-primeiro-ano/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/namoro-primeiro-ano/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-primeiro-ano/4.png","order":3},{"id":"ph_5","type":"image","r2Key":"seed/exemplos/namoro-primeiro-ano/5.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-primeiro-ano/5.png","order":4}],"timeline":[{"date":"07/2025","title":"A festa onde tudo desandou","description":"Pro lado certo. Uma amizade perfeitamente boa, estragada no melhor estilo.","photoAssetId":"ph_1"},{"date":"07/2025","title":"Primeiro café da manhã","description":"Você queimou o pão e eu menti que estava ótimo.","photoAssetId":"ph_2"},{"date":"12/2025","title":"O dia da praia em que choveu","description":"Melhor dia de praia da história.","photoAssetId":"ph_3"},{"date":"03/2026","title":"Você conhecendo minha mãe","description":"Ela te aprovou antes de mim.","photoAssetId":"ph_4"},{"date":"hoje","title":"A gente","description":"Ainda com cara de primeiro beijo.","photoAssetId":"ph_5"}],"stats":[{"auto":"days_since_counter","label":"dias de nós"}],"letter":"Ícaro, faz um ano que a gente estragou uma amizade perfeitamente boa — e foi a melhor decisão que já tomamos. Um ano de primeiras vezes: primeiro café queimado, primeira chuva na praia, primeira vez que eu percebi que \"te amo\" escapa sozinho quando é verdade. Obrigada por tornar o comum a melhor parte do meu dia. Que a gente nunca perca a cara de primeiro beijo. — Marina","closingMessage":"◄◄ aperta o play na nossa história","theme":"vhs"}'::jsonb,
   'namoro-primeiro-ano', 21, true, CURRENT_TIMESTAMP),
  ('ex_namoro_a_gente_e_a_nina', 'namorado', 'O casal e a cachorra', 'namorados',
   '{"title":"A gente + a Nina","recipientName":"Paula","senderName":"Vitor","counter":{"targetDate":"2022-07-12","label":"dias de matilha"},"assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/namoro-a-gente-e-a-nina/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-a-gente-e-a-nina/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/namoro-a-gente-e-a-nina/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-a-gente-e-a-nina/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/namoro-a-gente-e-a-nina/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-a-gente-e-a-nina/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/namoro-a-gente-e-a-nina/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/namoro-a-gente-e-a-nina/4.png","order":3}],"timeline":[{"date":"ano 1","title":"Só a gente","description":"Dois delivery e uma série que nunca terminamos."},{"date":"ano 2","title":"O anúncio \"só pra ver\"","description":"Você me mandou um anúncio de adoção \"só pra ver\". Aham. Só pra ver."},{"date":"o dia da Nina","title":"Ela chegou","description":"Vomitou no carro em 15 minutos de estrada. Já era da família.","photoAssetId":"ph_1"},{"date":"ano 3","title":"O tênis (in memoriam)","description":"Ela destruiu seu tênis favorito. Você a perdoou em 4 segundos, recorde mundial.","photoAssetId":"ph_2"},{"date":"hoje","title":"Três habitantes","description":"Cama de casal com três habitantes, dois pagando aluguel.","photoAssetId":"ph_3"}],"stats":[{"auto":"days_since_counter","label":"dias juntos"},{"value":730,"suffix":"passeios","label":"de coleira"},{"value":1,"suffix":"tênis","label":"in memoriam"}],"letter":"Paula, quatro anos e eu ainda não sei o que amo mais: acordar com você ou com a Nina pisando na minha cara às 6h. Mentira, sei sim. Obrigado por ter mandado aquele anúncio \"só pra ver\" e por transformar nosso apartamento em lar com pelo no sofá. Você cuida de nós dois de um jeito que me faz querer ser tão bom quanto a Nina acha que eu sou. — Vitor","theme":"vhs"}'::jsonb,
   'namoro-a-gente-e-a-nina', 22, true, CURRENT_TIMESTAMP),
  ('ex_casamento_primeiro_ano', 'casamento', 'Primeiro ano de casados', 'casamento',
   '{"title":"Nosso primeiro ano de alianças","recipientName":"Tom","senderName":"Bea","counter":{"targetDate":"2025-07-11","label":"dias de \"meu marido\" e \"minha esposa\" sem cansar"},"assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/casamento-primeiro-ano/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-primeiro-ano/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/casamento-primeiro-ano/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-primeiro-ano/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/casamento-primeiro-ano/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-primeiro-ano/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/casamento-primeiro-ano/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-primeiro-ano/4.png","order":3},{"id":"ph_5","type":"image","r2Key":"seed/exemplos/casamento-primeiro-ano/5.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-primeiro-ano/5.png","order":4}],"timeline":[{"date":"07/2025","title":"O sim","description":"Sua voz falhou e a minha sumiu.","photoAssetId":"ph_1"},{"date":"07/2025","title":"A dança ensaiada 14 vezes","description":"Erramos mesmo assim. Os convidados amaram.","photoAssetId":"ph_2"},{"date":"07/2025","title":"O voo perdido","description":"Lua de mel: perdemos o voo e ganhamos uma noite em Lisboa.","photoAssetId":"ph_3"},{"date":"08/2025","title":"Primeira geladeira nossa","description":"Enchemos de ímã e de planos.","photoAssetId":"ph_4"},{"date":"hoje","title":"365 dias depois","description":"Mesma vontade de casar de novo.","photoAssetId":"ph_5"}],"stats":[{"auto":"days_since_counter","label":"dias de casados"},{"value":1,"suffix":"voo perdido","label":"que virou história"},{"value":52,"suffix":"sextas","label":"de pizza no sofá"}],"letter":"Tom, um ano atrás sua voz falhou no altar e eu entendi tudo o que você não conseguiu falar. Este primeiro ano teve mais boleto que lua de mel, mais rotina que festa — e ainda assim, casar com você continua sendo a coisa mais certa que eu já fiz. Obrigada por transformar segunda-feira em lugar bom. Que a gente erre a dança juntos pra sempre. — Bea","theme":"vhs"}'::jsonb,
   'casamento-primeiro-ano', 23, true, CURRENT_TIMESTAMP),
  ('ex_casamento_de_2_viramos_4', 'casamento', '10 anos, com filhos', 'casamento',
   '{"title":"De 2 viramos 4 (e um papagaio)","recipientName":"Dani","senderName":"Fê","counter":{"targetDate":"2016-06-04","label":"dias de time em campo"},"assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/casamento-de-2-viramos-4/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-de-2-viramos-4/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/casamento-de-2-viramos-4/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-de-2-viramos-4/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/casamento-de-2-viramos-4/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-de-2-viramos-4/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/casamento-de-2-viramos-4/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-de-2-viramos-4/4.png","order":3},{"id":"ph_5","type":"image","r2Key":"seed/exemplos/casamento-de-2-viramos-4/5.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-de-2-viramos-4/5.png","order":4}],"timeline":[{"date":"2016","title":"Festa pequena, planos gigantes","description":"Casamos no quintal e ninguém queria ir embora.","photoAssetId":"ph_1"},{"date":"2018","title":"O positivo no banheiro","description":"Você gritou tão alto que a vizinha bateu na parede.","photoAssetId":"ph_2"},{"date":"2019","title":"Chegou o Théo","description":"Dormir virou lenda urbana.","photoAssetId":"ph_3"},{"date":"2022","title":"Chegou a Alice, com pressa","description":"Quase nasceu no Uber. O motorista ganhou 5 estrelas e terapia."},{"date":"2024","title":"O papagaio Juca","description":"Herdado do seu tio. Fala \"cadê o boleto\" melhor que nós dois.","photoAssetId":"ph_4"},{"date":"2026","title":"10 anos","description":"A casa é barulhenta, bagunçada e exatamente o que a gente pediu.","photoAssetId":"ph_5"}],"stats":[{"auto":"days_since_counter","label":"dias de casados"},{"value":2,"suffix":"humanos","label":"produzidos"},{"value":14000,"suffix":"fraldas","label":"estimativa conservadora"}],"letter":"Dani, dez anos atrás eu prometi te amar na alegria e na tristeza. Ninguém avisou da terceira opção: na exaustão. E olha que descoberta — é nela que eu mais te amo. Te vendo domar birra às 3h da manhã, rir no meio do caos, segurar a nossa casa com uma mão e a minha mão com a outra. A gente virou 4 (e um papagaio), mas no fim do dia, quando todo mundo dorme, ainda somos aqueles 2. Sempre seremos. — Fê","theme":"vhs"}'::jsonb,
   'casamento-de-2-viramos-4', 24, true, CURRENT_TIMESTAMP),
  ('ex_casamento_bodas_ouro', 'casamento', 'Bodas de ouro', 'casamento',
   '{"title":"50 anos de nós","recipientName":"Vó Cida & Vô Antônio","senderName":"seus netos","counter":{"targetDate":"1976-06-12","label":"dias de mão dada"},"assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/casamento-bodas-ouro/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-bodas-ouro/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/casamento-bodas-ouro/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-bodas-ouro/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/casamento-bodas-ouro/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-bodas-ouro/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/casamento-bodas-ouro/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-bodas-ouro/4.png","order":3},{"id":"ph_5","type":"image","r2Key":"seed/exemplos/casamento-bodas-ouro/5.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/casamento-bodas-ouro/5.png","order":4}],"timeline":[{"date":"1974","title":"O baile","description":"Vô pediu uma dança e pisou no pé dela duas vezes. Ela aceitou a terceira.","photoAssetId":"ph_1"},{"date":"1976","title":"O casamento","description":"Na cidade pequena. A festa acabou quando acabou a sanfona.","photoAssetId":"ph_4"},{"date":"anos 80","title":"Quatro filhos e uma venda","description":"E a fama do melhor pão da rua."},{"date":"anos 90","title":"Recomeço na capital","description":"Atrás dos filhos. Recomeçar aos 45 também é coragem.","photoAssetId":"ph_2"},{"date":"2010","title":"Primeira neta","description":"Vô inaugurou o posto de avô-babão que ocupa até hoje.","photoAssetId":"ph_3"},{"date":"2026","title":"A rosa do baile","description":"Vô ainda guarda a rosa (seca) do baile. A gente viu.","photoAssetId":"ph_5"}],"stats":[{"auto":"days_since_counter","label":"dias de casados"},{"value":4,"suffix":"filhos","label":"e uma multidão de netos"},{"value":1,"suffix":"rosa","label":"guardada desde 1974"}],"letter":"Vó, vô: metade da família nem tinha nascido quando vocês já eram história. A gente cresceu ouvindo do baile, da sanfona, do pão que sustentou quatro filhos. Mas o que a gente mais aprendeu foi olhando: o senhor descascando laranja pra ela todo santo dia, ela guardando o pedaço maior pro senhor. Cinquenta anos e vocês ainda se escolhem no café da manhã. Se amor tiver receita, a gente quer a de vocês. — Seus netos (todos, até o que só pensa em videogame)","closingMessage":"◄◄ algumas fitas nunca desgastam","theme":"vhs"}'::jsonb,
   'casamento-bodas-ouro', 25, true, CURRENT_TIMESTAMP),
  ('ex_pais_primeiro_dia', 'pai', 'Primeiro Dia dos Pais', 'pais',
   '{"title":"Seu primeiro Dia dos Pais","recipientName":"Gabriel","senderName":"Miguel (e a mamãe)","counter":{"targetDate":"2025-12-14","label":"dias sendo o pai do Miguel"},"assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/pais-primeiro-dia/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-primeiro-dia/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/pais-primeiro-dia/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-primeiro-dia/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/pais-primeiro-dia/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-primeiro-dia/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/pais-primeiro-dia/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-primeiro-dia/4.png","order":3},{"id":"ph_5","type":"image","r2Key":"seed/exemplos/pais-primeiro-dia/5.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-primeiro-dia/5.png","order":4}],"timeline":[{"date":"dia 1","title":"O dia em que você virou pai","description":"E eu me apaixonei de novo.","photoAssetId":"ph_1"},{"date":"semana 1","title":"Primeira troca de fralda","description":"22 minutos, 3 tentativas, 1 vitória.","photoAssetId":"ph_2"},{"date":"mês 2","title":"Geneticamente comprovado","description":"Vocês dois dormindo igual, de boca aberta.","photoAssetId":"ph_3"},{"date":"mês 4","title":"O banho","description":"Molhou mais você do que ele.","photoAssetId":"ph_4"},{"date":"mês 7","title":"Primeiro \"papapa\"","description":"Você jura que foi \"papai\". Deixa.","photoAssetId":"ph_5"}],"stats":[{"auto":"days_since_counter","label":"dias de paternidade"},{"value":1400,"suffix":"madrugadas","label":"interrompidas sem perder a ternura"},{"value":1,"suffix":"riso","label":"que valeu tudo"}],"letter":"Pai, eu ainda não sei falar, então a mamãe está escrevendo. Ela mandou dizer que te ver comigo no colo é a coisa mais bonita que ela já viu — e ela viu o mar. Que você acorda de madrugada sem reclamar (quase), que canta desafinado igual eu gosto, e que eu ganhei na loteria dos pais. Feliz primeiro Dia dos Pais. Dos infinitos que vêm por aí, esse é o que você nunca vai esquecer. — Miguel (7 meses, 8 quilos de amor por você)","theme":"vhs"}'::jsonb,
   'pais-primeiro-dia', 26, true, CURRENT_TIMESTAMP),
  ('ex_pais_tecnico_de_todas', 'pai', 'Pai e filho, mesmo time', 'pais',
   '{"title":"Meu técnico de todas as horas","recipientName":"pai","senderName":"seu eterno camisa 10","assets":[{"id":"ph_1","type":"image","r2Key":"seed/exemplos/pais-tecnico-de-todas/1.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-tecnico-de-todas/1.png","order":0},{"id":"ph_2","type":"image","r2Key":"seed/exemplos/pais-tecnico-de-todas/2.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-tecnico-de-todas/2.png","order":1},{"id":"ph_3","type":"image","r2Key":"seed/exemplos/pais-tecnico-de-todas/3.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-tecnico-de-todas/3.png","order":2},{"id":"ph_4","type":"image","r2Key":"seed/exemplos/pais-tecnico-de-todas/4.png","url":"https://pub-8f28e4405c4f45469ff2b69fce520c5c.r2.dev/seed/exemplos/pais-tecnico-de-todas/4.png","order":3}],"timeline":[{"date":"2003","title":"Minha primeira bola","description":"Você narrou meu primeiro gol contra o portão como se fosse final de Copa.","photoAssetId":"ph_1"},{"date":"2008","title":"Nunca faltou","description":"Você saía do turno cansado e ainda ia comigo pro treino. Eu contei.","photoAssetId":"ph_2"},{"date":"2014","title":"O 7x1 junto","description":"\"Filho, tem derrota que vira história.\" Uso isso pra tudo até hoje."},{"date":"2018","title":"O joelho e a frase","description":"\"Muda o sonho, não muda o time que a gente é.\"","photoAssetId":"ph_3"},{"date":"2026","title":"Mesmo sofá, mesmo time","description":"E eu não trocaria por camarote nenhum.","photoAssetId":"ph_4"}],"stats":[{"value":480,"suffix":"treinos","label":"com plateia de 1"},{"value":23,"suffix":"anos","label":"de arquibancada"},{"value":1,"suffix":"lema","label":"pra vida inteira"}],"letter":"Pai, você nunca me cobrou gol. Me cobrou caráter. Aprendi a perder no futebol e a ganhar na vida ouvindo você narrar meus erros como se fossem lances de gênio. Quando meu joelho estourou junto com meu sonho, você não deixou estourar o resto. \"Muda o sonho, não muda o time.\" Nosso time, velho, não rebaixa nunca. Feliz Dia dos Pais. — Seu camisa 10","theme":"vhs"}'::jsonb,
